<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Personal Expense Tracker</title>
<style>
  *, *::before, *::after { box-sizing: border-box; }
  body {
    font-family: system-ui, -apple-system, sans-serif;
    max-width: 860px;
    margin: 2rem auto;
    padding: 0 1rem;
    color: #222;
    background: #f9f9fb;
  }
  h1 { font-size: 1.5rem; margin-bottom: 1.5rem; }
  h2 { font-size: 1.15rem; margin-top: 1.8rem; margin-bottom: 0.6rem; }

  /* Form */
  .entry-form {
    display: grid;
    grid-template-columns: 1fr 1fr;
    gap: 0.6rem 1rem;
    background: #fff;
    padding: 1rem;
    border-radius: 8px;
    border: 1px solid #ddd;
  }
  .entry-form label { font-weight: 600; font-size: 0.9rem; }
  .entry-form input, .entry-form select {
    padding: 0.45rem 0.5rem;
    border: 1px solid #bbb;
    border-radius: 4px;
    font-size: 0.95rem;
  }
  .entry-form button {
    grid-column: span 2;
    padding: 0.6rem;
    background: #2563eb;
    color: #fff;
    border: none;
    border-radius: 4px;
    font-size: 1rem;
    cursor: pointer;
  }
  .entry-form button:hover { background: #1d4ed8; }

  #form-error {
    grid-column: span 2;
    color: #dc2626;
    font-weight: 600;
    min-height: 1.2em;
    font-size: 0.9rem;
  }

  /* Filters */
  .filters {
    display: flex;
    gap: 1rem;
    align-items: center;
    flex-wrap: wrap;
    background: #fff;
    padding: 0.8rem 1rem;
    border-radius: 8px;
    border: 1px solid #ddd;
    margin-top: 1.5rem;
  }
  .filters label { font-weight: 600; font-size: 0.9rem; }
  .filters select, .filters input[type="date"] {
    padding: 0.35rem 0.45rem;
    border: 1px solid #bbb;
    border-radius: 4px;
    font-size: 0.9rem;
  }

  /* Summary */
  .summary-bar {
    display: flex;
    gap: 2rem;
    align-items: baseline;
    flex-wrap: wrap;
    margin-top: 1rem;
  }
  #total { font-size: 1.3rem; font-weight: 700; }
  .cat-total { font-size: 0.95rem; }

  /* Expense list */
  .expense-list { margin-top: 1rem; }
  .expense {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 0.6rem 0.8rem;
    border-bottom: 1px solid #eee;
    font-size: 0.95rem;
  }
  .expense:last-child { border-bottom: none; }
  .expense.hidden { display: none; }
  .exp-info { flex: 1; }
  .exp-cat { font-weight: 600; text-transform: capitalize; margin-right: 0.5rem; }
  .exp-date { color: #666; font-size: 0.85rem; }
  .exp-note { color: #888; font-style: italic; font-size: 0.85rem; margin-left: 0.5rem; }
  .exp-amount { font-weight: 700; margin-right: 1rem; white-space: nowrap; }
  .exp-del {
    background: #dc2626;
    color: #fff;
    border: none;
    border-radius: 4px;
    padding: 0.3rem 0.7rem;
    cursor: pointer;
    font-size: 0.85rem;
  }
  .exp-del:hover { background: #b91c1c; }

  .no-expenses { color: #888; font-style: italic; padding: 1rem 0; }
</style>
</head>
<body>

<h1>Personal Expense Tracker</h1>

<!-- Entry Form -->
<form id="expense-form" class="entry-form">
  <div id="form-error"></div>
  <label for="amount">Amount ($)</label>
  <input type="number" id="amount" step="0.01" min="0" placeholder="0.00">

  <label for="category">Category</label>
  <select id="category">
    <option value="groceries">Groceries</option>
    <option value="transport">Transport</option>
    <option value="bills">Bills</option>
    <option value="fun">Fun</option>
  </select>

  <label for="date">Date</label>
  <input type="date" id="date">

  <label for="note">Note (optional)</label>
  <input type="text" id="note" placeholder="e.g. Weekly shopping">

  <button type="submit" id="add-expense">Add Expense</button>
</form>

<!-- Filters -->
<div class="filters">
  <label for="filter-category">Category:</label>
  <select id="filter-category">
    <option value="all">All</option>
    <option value="groceries">Groceries</option>
    <option value="transport">Transport</option>
    <option value="bills">Bills</option>
    <option value="fun">Fun</option>
  </select>

  <label for="filter-from">From:</label>
  <input type="date" id="filter-from">

  <label for="filter-to">To:</label>
  <input type="date" id="filter-to">
</div>

<!-- Summary -->
<div class="summary-bar">
  <span>Total: <span id="total">0.00</span></span>
  <span class="cat-total" data-cat="groceries"></span>
  <span class="cat-total" data-cat="transport"></span>
  <span class="cat-total" data-cat="bills"></span>
  <span class="cat-total" data-cat="fun"></span>
</div>

<!-- Expense List -->
<h2>Expenses</h2>
<div id="expense-list" class="expense-list"></div>

<script>
(function() {
  const STORAGE_KEY = 'expense_tracker_data';
  const CATEGORIES = ['groceries', 'transport', 'bills', 'fun'];

  // DOM refs
  const form = document.getElementById('expense-form');
  const amountInput = document.getElementById('amount');
  const categorySelect = document.getElementById('category');
  const dateInput = document.getElementById('date');
  const noteInput = document.getElementById('note');
  const formError = document.getElementById('form-error');
  const expenseListEl = document.getElementById('expense-list');
  const totalEl = document.getElementById('total');
  const filterCategory = document.getElementById('filter-category');
  const filterFrom = document.getElementById('filter-from');
  const filterTo = document.getElementById('filter-to');

  // State
  let expenses = loadExpenses();

  function loadExpenses() {
    try {
      const raw = localStorage.getItem(STORAGE_KEY);
      return raw ? JSON.parse(raw) : [];
    } catch(e) {
      return [];
    }
  }

  function saveExpenses() {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(expenses));
  }

  // Set default date to today
  dateInput.value = new Date().toISOString().slice(0, 10);

  // Form submission
  form.addEventListener('submit', function(e) {
    e.preventDefault();
    formError.textContent = '';

    const amountVal = amountInput.value.trim();
    const dateVal = dateInput.value.trim();
    const categoryVal = categorySelect.value;
    const noteVal = noteInput.value.trim();

    // Validation
    if (!amountVal || isNaN(Number(amountVal)) || Number(amountVal) <= 0) {
      formError.textContent = 'Please enter a valid positive amount.';
      return;
    }
    if (!dateVal) {
      formError.textContent = 'Please select a date.';
      return;
    }

    const expense = {
      id: Date.now().toString(36) + Math.random().toString(36).slice(2, 7),
      amount: parseFloat(Number(amountVal).toFixed(2)),
      category: categoryVal,
      date: dateVal,
      note: noteVal,
      createdAt: new Date().toISOString()
    };

    expenses.unshift(expense); // newest first
    saveExpenses();
    renderAll();

    // Reset amount field only; keep other fields for convenience
    amountInput.value = '';
    amountInput.focus();
  });

  // Delete handler (event delegation)
  expenseListEl.addEventListener('click', function(e) {
    if (e.target.classList.contains('exp-del')) {
      const row = e.target.closest('.expense');
      const id = row.dataset.id;
      expenses = expenses.filter(function(exp) { return exp.id !== id; });
      saveExpenses();
      renderAll();
    }
  });

  // Filter change handlers
  filterCategory.addEventListener('change', renderAll);
  filterFrom.addEventListener('change', renderAll);
  filterTo.addEventListener('change', renderAll);

  function getFilteredExpenses() {
    const catFilter = filterCategory.value;
    const fromVal = filterFrom.value;
    const toVal = filterTo.value;

    return expenses.filter(function(exp) {
      if (catFilter !== 'all' && exp.category !== catFilter) return false;
      if (fromVal && exp.date < fromVal) return false;
      if (toVal && exp.date > toVal) return false;
      return true;
    });
  }

  function renderAll() {
    const filtered = getFilteredExpenses();

    // Render list
    expenseListEl.innerHTML = '';
    if (filtered.length === 0) {
      expenseListEl.innerHTML = '<div class="no-expenses">No expenses to display.</div>';
    } else {
      filtered.forEach(function(exp) {
        const row = document.createElement('div');
        row.className = 'expense';
        row.dataset.id = exp.id;

        const noteHtml = exp.note ? '<span class="exp-note">' + escapeHtml(exp.note) + '</span>' : '';

        row.innerHTML =
          '<span class="exp-info">' +
            '<span class="exp-cat">' + escapeHtml(exp.category) + '</span> ' +
            '<span class="exp-date">' + exp.date + '</span>' +
            noteHtml +
          '</span>' +
          '<span class="exp-amount">$' + formatNum(exp.amount) + '</span>' +
          '<button class="exp-del" type="button">Delete</button>';

        expenseListEl.appendChild(row);
      });
    }

    // Compute totals
    let total = 0;
    const catTotals = {};
    CATEGORIES.forEach(function(c) { catTotals[c] = 0; });

    filtered.forEach(function(exp) {
      total += exp.amount;
      if (catTotals.hasOwnProperty(exp.category)) {
        catTotals[exp.category] += exp.amount;
      }
    });

    // Round to avoid floating point drift
    total = Math.round(total * 100) / 100;
    for (var c in catTotals) {
      if (catTotals.hasOwnProperty(c)) {
        catTotals[c] = Math.round(catTotals[c] * 100) / 100;
      }
    }

    totalEl.textContent = formatNum(total);

    // Per-category summaries
    document.querySelectorAll('.cat-total').forEach(function(el) {
      const cat = el.getAttribute('data-cat');
      if (catTotals.hasOwnProperty(cat)) {
        el.textContent = escapeHtml(cat) + ': $' + formatNum(catTotals[cat]);
      } else {
        el.textContent = '';
      }
    });
  }

  function formatNum(n) {
    return n.toFixed(2);
  }

  function escapeHtml(str) {
    var div = document.createElement('div');
    div.appendChild(document.createTextNode(str));
    return div.innerHTML;
  }

  // Initial render
  renderAll();
})();
</script>

</body>
</html>
